import{_ as n,o as s,c as a,ae as l}from"./chunks/framework.CFyvOAXl.js";const t="/img/vuepress/node-download.png",i="/img/vuepress/node-version.png",r="/img/vuepress/npm-run-dev.png",p="/img/vuepress/localhost-site.png",o="/img/vuepress/nginx-config.png",c="/img/vuepress/nginx-ip.png",f=JSON.parse('{"title":"使用vuePress搭建个人博客","description":"","frontmatter":{},"headers":[],"relativePath":"program/front/vuePress.md","filePath":"program/front/vuePress.md","lastUpdated":1777567730000}'),d={name:"program/front/vuePress.md"};function u(g,e,h,m,b,v){return s(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="使用vuepress搭建个人博客" tabindex="-1">使用vuePress搭建个人博客 <a class="header-anchor" href="#使用vuepress搭建个人博客" aria-label="Permalink to &quot;使用vuePress搭建个人博客&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#一、安装node-js">一、安装node.js</a></li><li><a href="#二、安装vuepress-搭建博客框架">二、安装vuePress,搭建博客框架</a></li><li><a href="#三、安装nginx">三、安装nginx</a></li><li><a href="#四、域名解析">四、域名解析</a></li><li><a href="#五、开发小知识点">五、开发小知识点</a></li></ul></nav><h2 id="一、安装node-js" tabindex="-1">一、安装node.js <a class="header-anchor" href="#一、安装node-js" aria-label="Permalink to &quot;一、安装node.js&quot;">​</a></h2><ol><li>进入<a href="https://nodejs.org/en/download/" target="_blank" rel="noreferrer">node.js下载页面</a>，根据操作系统类型选择特定版本下载。 <img src="'+t+'" alt="node-download-pic"></li><li>MacOS下，点击node-v12.pkg直接安装，各自安装至以下目录</li></ol><ul><li>Node.js v12.14.1 to /usr/local/bin/node</li><li>npm v6.13.4 to /usr/local/bin/npm</li></ul><ol start="3"><li>安装完成后，在terminal下，使用以下命令查看版本号</li></ol><ul><li>node -v</li><li>npm -v <img src="'+i+'" alt="node-version-pic"></li></ul><h2 id="二、安装vuepress-搭建博客框架" tabindex="-1">二、安装vuePress,搭建博客框架 <a class="header-anchor" href="#二、安装vuepress-搭建博客框架" aria-label="Permalink to &quot;二、安装vuePress,搭建博客框架&quot;">​</a></h2><ol><li>命令行输入：npm install -g vuepress 全局安装vuepress</li><li>搭建博客框架</li></ol><p>2.1 创建博客目录 mkdir myBlog</p><p>2.2 创建子目录</p><ul><li>/docs</li><li>/docs/.vuepress</li><li>/docs/</li></ul><p>2.3 创建js文件</p><ul><li>config.js</li><li>nav.js</li><li>sidebar.js</li></ul><p>2.4 然后按照<a href="https://vuepress.vuejs.org/zh/guide/" target="_blank" rel="noreferrer">vuepress官方文档</a>编写各个文件的内容。</p><p>2.5 本地调试</p><ul><li>构建静态文件 npm run build</li><li>发布 npm run dev 出现如下图片，即编译成功。 <img src="'+r+'" alt="npm-run-dev-pic"> 成功后，在浏览器窗口，输入 <a href="http://localhost:8080/" target="_blank" rel="noreferrer">http://localhost:8080/</a> 访问本地网站 <img src="'+p+'" alt="localhost-site-pic"></li></ul><h2 id="三、安装nginx" tabindex="-1">三、安装nginx <a class="header-anchor" href="#三、安装nginx" aria-label="Permalink to &quot;三、安装nginx&quot;">​</a></h2><blockquote><p>本文档的开发环境：</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:center;">类别</th><th style="text-align:center;">环境</th><th style="text-align:center;">备注</th></tr></thead><tbody><tr><td style="text-align:center;">服务器</td><td style="text-align:center;">弹性云ECS</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">操作系统</td><td style="text-align:center;">CentOS7</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">ssh工具</td><td style="text-align:center;">Royal TSX</td><td style="text-align:center;"></td></tr></tbody></table><ol><li>添加yum源 sudo rpm -ivh <a href="http://nginx.org/packages/centos/7/noarch/RPMS/nginx-release-centos-7-0.el7.ngx.noarch.rpm" target="_blank" rel="noreferrer">http://nginx.org/packages/centos/7/noarch/RPMS/nginx-release-centos-7-0.el7.ngx.noarch.rpm</a></li><li>安装nginx<br> sudo yum install nginx</li><li>查看nginx安装路径<br> rpm -ql nginx <img src="'+o+`" alt="nginx-config-pic"></li><li>本地编译dist包，scp到服务器上 scp -r dist <a href="mailto:root@47.107.82.83" target="_blank" rel="noreferrer">root@47.107.82.83</a>:/opt/www/blog</li><li>编辑nginx配置文件 首先注释掉这一行</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># include /etc/nginx/conf.d/*.conf;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后，编写server部分</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>server {</span></span>
<span class="line"><span>      listen  80;</span></span>
<span class="line"><span>      server_name  jacenhu.site;</span></span>
<span class="line"><span>      root /opt/www/blog/dist;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>      location / {</span></span>
<span class="line"><span>        #root html</span></span>
<span class="line"><span>        root  /opt/www/blog/dist;</span></span>
<span class="line"><span>        index  index.html index.htm;</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>最后，检查配置文件是否正确 执行，nginx -t ，若出现以下两句，则语法无错误</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nginx: the configuration file /etc/nginx/nginx.conf syntax is ok</span></span>
<span class="line"><span>nginx: configuration file /etc/nginx/nginx.conf test is successfu</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol start="6"><li>一些nginx的常用命令</li></ol><p>6.1 卸载nginx rpm -e nginx</p><p>6.2 服务启动/停止</p><ul><li>设置开机启动 sudo systemctl enable nginx</li><li>启动服务 sudo systemctl start nginx</li><li>重启服务 sudo systemctl restart nginx nginx -s reload</li></ul><ol start="7"><li>配置完成后，地址栏输入: <a href="http://ip" target="_blank" rel="noreferrer">http://ip</a>，即可访问 如： <a href="http://X.X.X.X" target="_blank" rel="noreferrer">http://X.X.X.X</a><img src="`+c+'" alt="nginx-ip-pic"></li></ol><h2 id="四、域名解析" tabindex="-1">四、域名解析 <a class="header-anchor" href="#四、域名解析" aria-label="Permalink to &quot;四、域名解析&quot;">​</a></h2><blockquote><p>每次通过<a href="http://xn--ip-7j3d2j35zq9z" target="_blank" rel="noreferrer">http://ip方式登录</a>，需要输入很多数字，比较麻烦。因此申请一个简易好记的域名十分重要。</p></blockquote><ol><li>此前已经申请好了域名 www.jancehu.site，通过云DNS解析，将其映射到X.X.X.X</li></ol><ul><li>注：域名解析是指把域名指向网站空间IP</li></ul><ol start="2"><li>访问 <a href="http://www.jacenhu.site" target="_blank" rel="noreferrer">www.jacenhu.site</a></li></ol><h2 id="五、开发小知识点" tabindex="-1">五、开发小知识点 <a class="header-anchor" href="#五、开发小知识点" aria-label="Permalink to &quot;五、开发小知识点&quot;">​</a></h2>',37)])])}const _=n(d,[["render",u]]);export{f as __pageData,_ as default};
